package ccxt

type Pacifica struct {
	*PacificaCore
	Core          *PacificaCore
	exchangeTyped *ExchangeTyped
}

func NewPacifica(userConfig map[string]interface{}) *Pacifica {
	p := NewPacificaCore()
	p.Init(userConfig)
	return &Pacifica{
		PacificaCore:  p,
		Core:          p,
		exchangeTyped: NewExchangeTyped(&p.Exchange),
	}
}
func NewPacificaFromCore(core *PacificaCore) *Pacifica {
	return &Pacifica{
		PacificaCore:  core,
		Core:          core,
		exchangeTyped: NewExchangeTyped(&core.Exchange),
	}
}

